// Initialize attempt counter and refinement hints
const staticData = $getWorkflowStaticData('global');
staticData.bgAttempts = 0;
staticData.refinementHints = '';
staticData.rejectionReasons = [];
return $input.all();

const p = $('Event Parameters').first().json;
const staticData = $getWorkflowStaticData('global');
staticData.bgAttempts = (staticData.bgAttempts || 0) + 1;

// ── Style presets ──
const STYLES = {
  photorealistic: {
    pos: [
      'A cinematic photograph: {concept}.',
      'Shot on 35mm film, shallow depth of field, golden hour lighting.',
      'Professional color grading, warm tones, inviting atmosphere.'
    ],
    neg: 'cartoon, illustration, painting, anime, 3d render, cgi, drawing, sketch'
  },
  anime: {
    pos: [
      'A vibrant anime illustration: {concept}.',
      'Studio Ghibli inspired, cel-shaded, rich saturated palette.',
      'Soft ambient lighting, detailed background art, dreamy atmosphere.'
    ],
    neg: 'photorealistic, photograph, 3d render, cgi, western cartoon, low detail'
  },
  western_cartoon: {
    pos: [
      'A stylized cartoon illustration: {concept}.',
      'Bold outlines, flat color fills, playful exaggerated proportions.',
      'Bright cheerful palette, clean vector-style rendering.'
    ],
    neg: 'photorealistic, photograph, anime, 3d render, dark, gritty'
  },
  scifi: {
    pos: [
      'A futuristic sci-fi scene: {concept}.',
      'Neon accents, holographic elements, sleek metallic surfaces.',
      'Dramatic volumetric lighting, cyberpunk atmosphere, high-tech environment.'
    ],
    neg: 'cartoon, hand-drawn, vintage, rustic, low-tech, blurry'
  },
  watercolor: {
    pos: [
      'A delicate watercolor painting: {concept}.',
      'Soft washes of color, visible paper texture, gentle bleeding edges.',
      'Impressionistic detail, pastel and muted tones, artistic brushwork.'
    ],
    neg: 'photorealistic, photograph, sharp lines, 3d render, digital art, cartoon'
  },
  retro_poster: {
    pos: [
      'A vintage retro poster illustration: {concept}.',
      'Mid-century modern aesthetic, limited color palette, screen-print texture.',
      'Bold geometric shapes, grain overlay, nostalgic warm tones.'
    ],
    neg: 'photorealistic, photograph, 3d render, anime, hyper-detailed'
  }
};

const styleKey = (p.style_preset || 'photorealistic').toLowerCase().replace(/[\s-]/g, '_');
const style = STYLES[styleKey] || STYLES.photorealistic;

// Flyer directives — keeps clean zones for text overlay
const flyerDirectives = [
  'Smooth clean bokeh areas in the upper third and lower third of the frame.',
  'Main subject centered in middle third of composition.',
  'No text, no writing, no letters, no signs, no symbols.',
  'Pure background art with no graphic design elements.',
  'Tall portrait composition 9:16.'
];

// Inject refinement hints from prior rejection (if any)
const refinementLine = staticData.refinementHints
  ? `Additional direction: ${staticData.refinementHints}`
  : '';

const bgPrompt = [
  ...style.pos.map(line => line.replace('{concept}', p.style_concept)),
  ...flyerDirectives,
  refinementLine
].filter(Boolean).join(' ');

const negPrompt = [
  'text, writing, letters, words, numbers, watermark, logo, signs, symbols,',
  'UI, overlay, graphic design, borders, captions, labels,',
  style.neg + ',',
  'blurry, low quality, deformed, disfigured, noisy, grainy,',
  'cluttered composition, busy background, overlapping subjects'
].join(' ');

// Use 832x1472 (9:16, model-friendly multiples of 64) then upscale in SVG/PNG step
// This reduces artifacts vs native 1080x1920 for SD3/Flux-family latents
const latentWidth = 832;
const latentHeight = 1472;

const workflow = {
  "9": {
    inputs: { filename_prefix: "flyer-bg", images: ["57:8", 0] },
    class_type: "SaveImage", _meta: { title: "Save Image" }
  },
  "57:30": {
    inputs: { clip_name: "qwen_3_4b.safetensors", type: "lumina2", device: "default" },
    class_type: "CLIPLoader", _meta: { title: "Load CLIP" }
  },
  "57:29": {
    inputs: { vae_name: "ae.safetensors" },
    class_type: "VAELoader", _meta: { title: "Load VAE" }
  },
  "57:34": {
    inputs: { text: negPrompt, clip: ["57:30", 0] },
    class_type: "CLIPTextEncode", _meta: { title: "Negative Prompt" }
  },
  "57:8": {
    inputs: { samples: ["57:3", 0], vae: ["57:29", 0] },
    class_type: "VAEDecode", _meta: { title: "VAE Decode" }
  },
  "57:28": {
    inputs: { unet_name: "z_image_turbo_bf16.safetensors", weight_dtype: "default" },
    class_type: "UNETLoader", _meta: { title: "Load Diffusion Model" }
  },
  "57:27": {
    inputs: { text: bgPrompt, clip: ["57:30", 0] },
    class_type: "CLIPTextEncode", _meta: { title: "Positive Prompt" }
  },
  "57:13": {
    inputs: { width: latentWidth, height: latentHeight, batch_size: 1 },
    class_type: "EmptySD3LatentImage", _meta: { title: "EmptySD3LatentImage" }
  },
  "57:11": {
    inputs: { shift: 3, model: ["57:28", 0] },
    class_type: "ModelSamplingAuraFlow", _meta: { title: "ModelSamplingAuraFlow" }
  },
  "57:3": {
    inputs: {
      seed: Math.floor(Math.random() * 2147483647),
      steps: 8, cfg: 1,
      sampler_name: "res_multistep", scheduler: "simple", denoise: 1,
      model: ["57:11", 0], positive: ["57:27", 0],
      negative: ["57:34", 0], latent_image: ["57:13", 0]
    },
    class_type: "KSampler", _meta: { title: "KSampler" }
  }
};

return [{
  json: {
    workflow,
    bgPrompt,
    negPrompt,
    styleKey,
    attempt: staticData.bgAttempts,
    refinementUsed: staticData.refinementHints || '(none)',
    rejectionHistory: staticData.rejectionReasons || []
  }
}];

const staticData = $getWorkflowStaticData('global');
staticData.pollCount = 0;
staticData.pollStartTime = Date.now();
return $input.all();

const staticData = $getWorkflowStaticData('global');
staticData.pollCount = (staticData.pollCount || 0) + 1;
const elapsed = Math.round((Date.now() - (staticData.pollStartTime || Date.now())) / 1000);

if (staticData.pollCount > 20) {
  throw new Error(
    `ComfyCloud job timed out after ${staticData.pollCount} polls (${elapsed}s). ` +
    `Last status: ${$input.first().json.status || 'unknown'}`
  );
}

return [{ json: { pollCount: staticData.pollCount, elapsedSeconds: elapsed, status: $input.first().json.status || 'unknown' } }];

const history = $input.first().json;
const images = [];

for (const [jobId, jobData] of Object.entries(history)) {
  const outputs = jobData.outputs || {};
  for (const [nodeId, nodeOutput] of Object.entries(outputs)) {
    if (nodeOutput && nodeOutput.images) {
      for (const img of nodeOutput.images) {
        images.push({
          filename: img.filename,
          subfolder: img.subfolder || '',
          type: img.type || 'output',
          download_url: `https://cloud.comfy.org/api/view?filename=${encodeURIComponent(img.filename)}&subfolder=${encodeURIComponent(img.subfolder || '')}&type=${img.type || 'output'}`
        });
      }
    }
  }
}

if (images.length === 0) {
  throw new Error('No images found in job history: ' + JSON.stringify(history).substring(0, 500));
}

// Return first image only (we generate one per job)
return [{ json: images[0] }];

// Upscale background from 832x1472 to 1080x1920 using sharp
// This gives us a working canvas at the final output resolution
let sharp;
try {
  sharp = require('sharp');
} catch (e) {
  throw new Error('sharp module not available in this n8n instance. Install with: npm install sharp (or enable NODE_FUNCTION_ALLOW_EXTERNAL=sharp)');
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');

const upscaled = await sharp(buffer)
  .resize(1080, 1920, { fit: 'cover', position: 'center' })
  .png({ quality: 95 })
  .toBuffer();

const meta = await sharp(upscaled).metadata();

return [{
  json: {
    width: meta.width,
    height: meta.height,
    format: meta.format,
    size_kb: Math.round(upscaled.length / 1024)
  },
  binary: {
    data: {
      data: upscaled.toString('base64'),
      mimeType: 'image/png',
      fileName: 'background_1080x1920.png',
      fileExtension: 'png'
    }
  }
}];

// Build vision prompt + payload for Claude
// Single call: appropriateness check + layout zone assignment
const event = $('Event Parameters').first().json;
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64Image = buffer.toString('base64');

const systemPrompt = `You are a professional graphic designer evaluating AI-generated background images for event flyers. Your job has two parts:

1. APPROPRIATENESS: Determine if the image is suitable for the given event. Consider subject match, mood/tone, visual quality (not blurry/deformed), and absence of unwanted elements (text, watermarks, people with distorted features).

2. LAYOUT: If approved, identify the optimal placement zones for flyer text elements. The canvas is 1080 wide x 1920 tall (9:16 portrait). Classify zones using a 3x3 grid:
   - Rows: TOP (0-640px), MIDDLE (640-1280px), BOTTOM (1280-1920px)
   - Cols: LEFT (0-360px), CENTER (360-720px), RIGHT (720-1080px)

For each text element, pick the ZONE with the cleanest visual area (smooth, low-detail, good contrast for white text).

Text elements to place:
- TITLE (largest, 3-4 lines max): the event name
- DETAILS (date, time, venue): supporting info block
- FEE_BADGE (small pill): price/cost indicator
- ORG_CREDIT (tiny): presenter line at very bottom

Return ONLY valid JSON. No prose, no markdown fences. Schema:
{
  "approved": true|false,
  "confidence": 0.0-1.0,
  "rejection_reasons": [] | ["specific issue 1", ...],
  "refinement_hint": "" | "guidance for regeneration, e.g. 'more sky area at top, less visual clutter'",
  "zones": {
    "title": "TOP_CENTER" | "TOP_LEFT" | "TOP_RIGHT" | "MIDDLE_CENTER" | ...,
    "details": "BOTTOM_CENTER" | ...,
    "fee_badge": "TOP_RIGHT" | "BOTTOM_LEFT" | ...,
    "org_credit": "BOTTOM_CENTER"
  },
  "text_color": "white" | "dark",
  "mood_tags": ["warm", "energetic", ...]
}

If approved is false, zones can be omitted. Confidence below 0.6 should trigger rejection.`;

const userText = `Event: "${event.event_title}"
Description concept: ${event.style_concept}
Date: ${event.event_date}
Venue: ${event.event_location_name}

Evaluate the attached image for this event and return the layout JSON.`;

const payload = {
  model: 'claude-sonnet-4-5',
  max_tokens: 1024,
  system: systemPrompt,
  messages: [
    {
      role: 'user',
      content: [
        {
          type: 'image',
          source: {
            type: 'base64',
            media_type: 'image/png',
            data: base64Image
          }
        },
        {
          type: 'text',
          text: userText
        }
      ]
    }
  ]
};

return [{
  json: { payload },
  binary: $input.first().binary
}];

// Parse vision response — tolerant of markdown fences and stray prose
const resp = $input.first().json;

if (!resp.content || !Array.isArray(resp.content)) {
  throw new Error('Malformed Claude response: ' + JSON.stringify(resp).substring(0, 500));
}

const rawText = resp.content
  .filter(b => b.type === 'text')
  .map(b => b.text)
  .join('\n')
  .trim();

// Strip markdown fences if present
let jsonStr = rawText.replace(/```json\s*/gi, '').replace(/```\s*$/g, '').trim();

// Try to extract the first {...} block if there's surrounding prose
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace >= 0 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse vision JSON. Raw: ${rawText.substring(0, 400)}`);
}

// Sanity-check required fields
if (typeof parsed.approved !== 'boolean') {
  throw new Error('Missing "approved" boolean in vision response');
}

// Validate zones if approved
const validZones = new Set([
  'TOP_LEFT', 'TOP_CENTER', 'TOP_RIGHT',
  'MIDDLE_LEFT', 'MIDDLE_CENTER', 'MIDDLE_RIGHT',
  'BOTTOM_LEFT', 'BOTTOM_CENTER', 'BOTTOM_RIGHT'
]);

if (parsed.approved) {
  const zones = parsed.zones || {};
  // Defaults if vision omitted any
  parsed.zones = {
    title: validZones.has(zones.title) ? zones.title : 'TOP_CENTER',
    details: validZones.has(zones.details) ? zones.details : 'BOTTOM_CENTER',
    fee_badge: validZones.has(zones.fee_badge) ? zones.fee_badge : 'MIDDLE_CENTER',
    org_credit: validZones.has(zones.org_credit) ? zones.org_credit : 'BOTTOM_CENTER'
  };
  parsed.text_color = (parsed.text_color === 'dark') ? 'dark' : 'white';
}

// Confidence gate
if (parsed.approved && typeof parsed.confidence === 'number' && parsed.confidence < 0.6) {
  parsed.approved = false;
  parsed.rejection_reasons = parsed.rejection_reasons || [];
  parsed.rejection_reasons.push(`Low confidence: ${parsed.confidence}`);
}

// Store rejection hint in static data for next regen
const staticData = $getWorkflowStaticData('global');
if (!parsed.approved) {
  staticData.refinementHints = parsed.refinement_hint || '';
  staticData.rejectionReasons = parsed.rejection_reasons || ['unspecified'];
}

return [{
  json: {
    approved: parsed.approved,
    confidence: parsed.confidence || null,
    rejection_reasons: parsed.rejection_reasons || [],
    refinement_hint: parsed.refinement_hint || '',
    zones: parsed.zones || {},
    text_color: parsed.text_color || 'white',
    mood_tags: parsed.mood_tags || [],
    attempt: staticData.bgAttempts,
    raw_response: rawText.substring(0, 500)
  },
  binary: $input.first().binary
}];

// Check if we've exhausted background regeneration attempts
const params = $('Event Parameters').first().json;
const staticData = $getWorkflowStaticData('global');
const maxAttempts = params.max_bg_attempts || 3;

if (staticData.bgAttempts >= maxAttempts) {
  throw new Error(
    `Vision rejected ${staticData.bgAttempts} generated backgrounds. ` +
    `Last reasons: ${(staticData.rejectionReasons || []).join('; ')}. ` +
    `Consider adjusting style_concept or style_preset.`
  );
}

return [{
  json: {
    attempt: staticData.bgAttempts,
    remaining: maxAttempts - staticData.bgAttempts,
    reasons: staticData.rejectionReasons,
    refinement: staticData.refinementHints
  }
}];

// Convert zone labels to pixel coordinates on the 1080x1920 canvas
// Returns text block positions with anchors (x, y, text-anchor)
const visionData = $input.first().json;

const ZONE_CENTERS = {
  // Each zone: {x, y, anchor, maxWidth}
  TOP_LEFT:      { x: 180,  y: 320,  anchor: 'start'  },
  TOP_CENTER:    { x: 540,  y: 320,  anchor: 'middle' },
  TOP_RIGHT:     { x: 900,  y: 320,  anchor: 'end'    },
  MIDDLE_LEFT:   { x: 180,  y: 960,  anchor: 'start'  },
  MIDDLE_CENTER: { x: 540,  y: 960,  anchor: 'middle' },
  MIDDLE_RIGHT:  { x: 900,  y: 960,  anchor: 'end'    },
  BOTTOM_LEFT:   { x: 180,  y: 1600, anchor: 'start'  },
  BOTTOM_CENTER: { x: 540,  y: 1600, anchor: 'middle' },
  BOTTOM_RIGHT:  { x: 900,  y: 1600, anchor: 'end'    }
};

const zones = visionData.zones;
const layout = {
  title:      ZONE_CENTERS[zones.title]      || ZONE_CENTERS.TOP_CENTER,
  details:    ZONE_CENTERS[zones.details]    || ZONE_CENTERS.BOTTOM_CENTER,
  fee_badge:  ZONE_CENTERS[zones.fee_badge]  || ZONE_CENTERS.MIDDLE_CENTER,
  org_credit: ZONE_CENTERS[zones.org_credit] || ZONE_CENTERS.BOTTOM_CENTER
};

return [{
  json: {
    ...visionData,
    layout,
    zones_resolved: {
      title: zones.title,
      details: zones.details,
      fee_badge: zones.fee_badge,
      org_credit: zones.org_credit
    }
  },
  binary: $input.first().binary
}];

// Compose SVG using vision-derived layout
const event = $('Event Parameters').first().json;
const visionData = $input.first().json;
const layout = visionData.layout;
const textColor = visionData.text_color === 'dark' ? '#1a1a1a' : '#ffffff';
const strokeColor = visionData.text_color === 'dark' ? 'rgba(255,255,255,0.4)' : 'rgba(0,0,0,0.5)';
const subtleTextColor = visionData.text_color === 'dark' ? 'rgba(26,26,26,0.75)' : 'rgba(255,255,255,0.85)';
const accentColor = event.color_accent || '#F59E0B';

// ── Access background PNG ──
const bgBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const bgBase64 = bgBuffer.toString('base64');
const bgHref = `data:image/png;base64,${bgBase64}`;

const title = (event.event_title || 'EVENT').toUpperCase();
const date = event.event_date || '';
const time = event.event_time || '';
const venueName = event.event_location_name || '';
const venueAddr = event.event_location_address || '';
const fees = event.event_fees || '';
const org = event.event_org || '';
const url = event.event_url || '';

// ── Title sizing ──
const titleLen = title.length;
let fontSize, maxCharsPerLine;
if (titleLen <= 14) { fontSize = 82; maxCharsPerLine = 14; }
else if (titleLen <= 20) { fontSize = 72; maxCharsPerLine = 20; }
else if (titleLen <= 30) { fontSize = 62; maxCharsPerLine = 18; }
else { fontSize = 52; maxCharsPerLine = 22; }

function wrapText(text, maxChars) {
  const words = text.split(' ');
  if (words.length <= 2) return [text];
  const lines = [];
  let current = '';
  for (const word of words) {
    if (current.length + word.length + 1 > maxChars && current.length > 0) {
      lines.push(current); current = word;
    } else {
      current = current ? current + ' ' + word : word;
    }
  }
  if (current) lines.push(current);
  if (lines.length > 1) {
    const last = lines[lines.length - 1];
    const prev = lines[lines.length - 2];
    if (last.length < prev.length * 0.4) {
      lines.pop();
      lines[lines.length - 1] = prev + ' ' + last;
    }
  }
  return lines;
}

const titleLines = wrapText(title, maxCharsPerLine);
const lineHeight = fontSize * 1.25;

// Position title block — center on layout.title.y, stack lines
const titleTotalHeight = titleLines.length * lineHeight;
const titleStartY = layout.title.y - (titleTotalHeight / 2) + fontSize * 0.8;

const titleSVG = titleLines.map((line, i) =>
  `<text x="${layout.title.x}" y="${titleStartY + i * lineHeight}" text-anchor="${layout.title.anchor}" ` +
  `font-family="'Arial Black', 'Helvetica Neue', Arial, sans-serif" ` +
  `font-size="${fontSize}" font-weight="900" fill="${textColor}" letter-spacing="2" ` +
  `paint-order="stroke" stroke="${strokeColor}" stroke-width="3">${line}</text>`
).join('\n  ');

// Accent line under title
const titleBlockBottom = titleStartY + (titleLines.length - 1) * lineHeight + 20;
const accentLineX = layout.title.anchor === 'middle'
  ? layout.title.x - 100
  : (layout.title.anchor === 'start' ? layout.title.x : layout.title.x - 200);
const accentLine = `<rect x="${accentLineX}" y="${titleBlockBottom}" width="200" height="4" rx="2" fill="${accentColor}" opacity="0.9"/>`;

// ── Details block ──
const dx = layout.details.x;
const dy = layout.details.y;
const dAnchor = layout.details.anchor;

const detailsSVG = `
  <text x="${dx}" y="${dy - 40}" text-anchor="${dAnchor}" font-family="'Arial Black', Arial, sans-serif" font-size="40" font-weight="bold" fill="${textColor}" letter-spacing="1">${date}</text>
  <text x="${dx}" y="${dy + 15}" text-anchor="${dAnchor}" font-family="Arial, Helvetica, sans-serif" font-size="34" fill="${subtleTextColor}">${time}</text>
  <rect x="${dx - (dAnchor === 'middle' ? 70 : 0) - (dAnchor === 'end' ? 140 : 0)}" y="${dy + 42}" width="140" height="2" rx="1" fill="${textColor}" opacity="0.3"/>
  <text x="${dx}" y="${dy + 90}" text-anchor="${dAnchor}" font-family="Arial, Helvetica, sans-serif" font-size="30" font-weight="bold" fill="${textColor}" opacity="0.95">${venueName}</text>
  <text x="${dx}" y="${dy + 130}" text-anchor="${dAnchor}" font-family="Arial, Helvetica, sans-serif" font-size="24" fill="${subtleTextColor}">${venueAddr}</text>
  ${url ? `<text x="${dx}" y="${dy + 210}" text-anchor="${dAnchor}" font-family="Arial, Helvetica, sans-serif" font-size="22" fill="${subtleTextColor}">${url}</text>` : ''}`;

// ── Fee badge ──
const feeBadgeWidth = Math.min(Math.max(fees.length * 22 + 60, 140), 400);
const feeFontSize = fees.length > 15 ? 22 : 30;
const fx = layout.fee_badge.x;
const fy = layout.fee_badge.y;
const fAnchor = layout.fee_badge.anchor;
let feeBadgeX;
if (fAnchor === 'middle') feeBadgeX = fx - feeBadgeWidth / 2;
else if (fAnchor === 'start') feeBadgeX = fx;
else feeBadgeX = fx - feeBadgeWidth;

const feeBadge = fees ? `
  <rect x="${feeBadgeX}" y="${fy - 28}" width="${feeBadgeWidth}" height="56" rx="28" fill="${accentColor}"/>
  <text x="${feeBadgeX + feeBadgeWidth/2}" y="${fy + 8}" text-anchor="middle" font-family="Arial, Helvetica, sans-serif" font-size="${feeFontSize}" font-weight="bold" fill="#1a1a1a">${fees}</text>` : '';

// ── Org credit (always pinned near bottom regardless of zone) ──
const orgCredit = `<text x="540" y="1840" text-anchor="middle" font-family="Arial, Helvetica, sans-serif" font-size="20" fill="${textColor}" opacity="0.55">Presented by ${org}</text>`;

// ── Scrim gradients over text zones for readability ──
// Build scrim rects based on which zones are used
const scrimZones = new Set([visionData.zones_resolved.title.split('_')[0], visionData.zones_resolved.details.split('_')[0]]);
let scrims = '';
if (scrimZones.has('TOP')) {
  scrims += `<rect x="0" y="0" width="1080" height="700" fill="url(#topFade)"/>`;
}
if (scrimZones.has('BOTTOM')) {
  scrims += `<rect x="0" y="1220" width="1080" height="700" fill="url(#bottomFade)"/>`;
}
if (scrimZones.has('MIDDLE')) {
  scrims += `<rect x="0" y="600" width="1080" height="720" fill="url(#middleFade)"/>`;
}

const fadeColor = visionData.text_color === 'dark' ? '255,255,255' : '0,0,0';

const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink"
     width="1080" height="1920" viewBox="0 0 1080 1920">
  <defs>
    <linearGradient id="topFade" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="rgb(${fadeColor})" stop-opacity="0.75"/>
      <stop offset="100%" stop-color="rgb(${fadeColor})" stop-opacity="0"/>
    </linearGradient>
    <linearGradient id="bottomFade" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="rgb(${fadeColor})" stop-opacity="0"/>
      <stop offset="100%" stop-color="rgb(${fadeColor})" stop-opacity="0.85"/>
    </linearGradient>
    <radialGradient id="middleFade" cx="0.5" cy="0.5" r="0.6">
      <stop offset="0%" stop-color="rgb(${fadeColor})" stop-opacity="0.6"/>
      <stop offset="100%" stop-color="rgb(${fadeColor})" stop-opacity="0"/>
    </radialGradient>
  </defs>

  <image href="${bgHref}" width="1080" height="1920" preserveAspectRatio="xMidYMid slice"/>

  ${scrims}

  ${titleSVG}
  ${accentLine}

  ${detailsSVG}

  ${feeBadge}

  ${orgCredit}

  <rect x="0" y="1908" width="1080" height="12" fill="${accentColor}" opacity="0.8"/>
</svg>`;

return [{
  json: { svg_length: svg.length, layout_used: visionData.zones_resolved },
  binary: {
    poster_svg: {
      data: Buffer.from(svg, 'utf-8').toString('base64'),
      mimeType: 'image/svg+xml',
      fileName: 'poster.svg',
      fileExtension: 'svg'
    }
  }
}];

// Rasterize SVG → PNG using sharp
let sharp;
try {
  sharp = require('sharp');
} catch (e) {
  throw new Error('sharp module not available. Set NODE_FUNCTION_ALLOW_EXTERNAL=sharp or install in n8n container.');
}

const event = $('Event Parameters').first().json;
const svgBuffer = await this.helpers.getBinaryDataBuffer(0, 'poster_svg');

const pngBuffer = await sharp(svgBuffer, { density: 150 })
  .resize(1080, 1920, { fit: 'contain' })
  .png({ quality: 95, compressionLevel: 8 })
  .toBuffer();

const safeName = (event.event_title || 'flyer').toLowerCase().replace(/[^a-z0-9]+/g, '_');
const filename = `flyer_${safeName}.png`;

return [{
  json: {
    event_title: event.event_title,
    filename,
    size_kb: Math.round(pngBuffer.length / 1024),
    dimensions: '1080x1920'
  },
  binary: {
    poster: {
      data: pngBuffer.toString('base64'),
      mimeType: 'image/png',
      fileName: filename,
      fileExtension: 'png'
    }
  }
}];
